    public Object getAccount(Object... optionalArgs)
    {
        // get current or provided bitmax sub-account
        Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
        Object account = this.safeValue(parameters, "account", Helpers.GetValue(this.options, "account"));
        Object lowercaseAccount = ((String)account).toLowerCase();
        return this.capitalize(lowercaseAccount);
    }

    /**
     * @method
     * @name ascendex#fetchCurrencies
     * @description fetches all available currencies on an exchange
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an associative dictionary of currencies
     */
    public java.util.concurrent.CompletableFuture<Object> fetchCurrencies(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.v2PublicGetAssets(parameters)).join();
            //
            //    {
            //        "code": "0",
            //        "data": [
            //            {
            //                "assetCode": "USDT",
            //                "assetName": "Tether",
            //                "precisionScale": 9,
            //                "nativeScale": 4,
            //                "blockChain": [
            //                    {
            //                        "chainName": "Solana",
            //                        "withdrawFee": "2.0",
            //                        "allowDeposit": true,
            //                        "allowWithdraw": true,
            //                        "minDepositAmt": "0.01",
            //                        "minWithdrawal": "4.0",
            //                        "numConfirmations": 1
            //                    },
            //                    ...
            //                ]
            //            },
            //         ]
            //    }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseCurrencies(data);
        });

    }

    public Object parseCurrency(Object rawCurrency)
    {
        Object id = this.safeString(rawCurrency, "assetCode");
        Object code = this.safeCurrencyCode(id);
        Object chains = this.safeList(rawCurrency, "blockChain", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object precision = this.parseNumber(this.parsePrecision(this.safeString(rawCurrency, "nativeScale")));
        Object networks = new java.util.HashMap<String, Object>() {{}};
        for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(chains)); j++)
        {
            Object networkEtnry = Helpers.GetValue(chains, j);
            Object networkId = this.safeString(networkEtnry, "chainName");
            Object networkCode = this.networkCodeToId(((String)networkId), code);
            Helpers.addElementToObject(networks, networkCode, new java.util.HashMap<String, Object>() {{
    put( "fee", AscendexCore.this.safeNumber(networkEtnry, "withdrawFee") );
    put( "active", null );
    put( "withdraw", AscendexCore.this.safeBool(networkEtnry, "allowWithdraw") );
    put( "deposit", AscendexCore.this.safeBool(networkEtnry, "allowDeposit") );
    put( "precision", precision );
    put( "limits", new java.util.HashMap<String, Object>() {{
        put( "amount", new java.util.HashMap<String, Object>() {{
            put( "min", null );
            put( "max", null );
        }} );
        put( "withdraw", new java.util.HashMap<String, Object>() {{
            put( "min", AscendexCore.this.safeNumber(networkEtnry, "minWithdrawal") );
            put( "max", null );
        }} );
        put( "deposit", new java.util.HashMap<String, Object>() {{
            put( "min", AscendexCore.this.safeNumber(networkEtnry, "minDepositAmt") );
            put( "max", null );
        }} );
    }} );
}});
        }
        // todo type: if (chainsLength === 0 && (assetName.endsWith (' Staking') || assetName.indexOf (' Reward ') >= 0 || assetName.indexOf ('Slot Auction') >= 0 || assetName.indexOf (' Freeze Asset') >= 0))
        return this.safeCurrencyStructure(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "code", code );
            put( "info", rawCurrency );
            put( "type", null );
            put( "margin", null );
            put( "name", AscendexCore.this.safeString(rawCurrency, "assetName") );
            put( "active", null );
            put( "deposit", null );
            put( "withdraw", null );
            put( "fee", null );
            put( "precision", precision );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "withdraw", new java.util.HashMap<String, Object>() {{
                    put( "min", AscendexCore.this.safeNumber(rawCurrency, "minWithdrawalAmt") );
                    put( "max", null );
                }} );
            }} );
            put( "networks", networks );
        }});
    }

    /**
     * @method
     * @name ascendex#fetchMarkets
     * @description retrieves data on all markets for ascendex
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object spotPromise = this.fetchSpotMarkets(parameters);
            Object contractPromise = this.fetchContractMarkets(parameters);
            var spotMarketscontractMarketsVariable = (Helpers.promiseAll(new java.util.ArrayList<Object>(java.util.Arrays.asList(spotPromise, contractPromise)))).join();
            var spotMarkets = ((java.util.List<Object>) spotMarketscontractMarketsVariable).get(0);
            var contractMarkets = ((java.util.List<Object>) spotMarketscontractMarketsVariable).get(1);
            return this.arrayConcat(spotMarkets, contractMarkets);
        });

    }

