    public Object parseBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", null );
            put( "datetime", null );
        }};
        Object balances = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balance = Helpers.GetValue(balances, i);
            Object code = this.safeCurrencyCode(this.safeString(balance, "asset"));
            Object account = this.account();
            Helpers.addElementToObject(account, "free", this.safeString(balance, "availableBalance"));
            Helpers.addElementToObject(account, "total", this.safeString(balance, "totalBalance"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

    public Object parseMarginBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", null );
            put( "datetime", null );
        }};
        Object balances = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(balances)); i++)
        {
            Object balance = Helpers.GetValue(balances, i);
            Object code = this.safeCurrencyCode(this.safeString(balance, "asset"));
            Object account = this.account();
            Helpers.addElementToObject(account, "free", this.safeString(balance, "availableBalance"));
            Helpers.addElementToObject(account, "total", this.safeString(balance, "totalBalance"));
            Object debt = this.safeString(balance, "borrowed");
            Object interest = this.safeString(balance, "interest");
            Helpers.addElementToObject(account, "debt", Precise.stringAdd(debt, interest));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

    public Object parseSwapBalance(Object response)
    {
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", response );
            put( "timestamp", null );
            put( "datetime", null );
        }};
        Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
        Object collaterals = this.safeList(data, "collaterals", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(collaterals)); i++)
        {
            Object balance = Helpers.GetValue(collaterals, i);
            Object code = this.safeCurrencyCode(this.safeString(balance, "asset"));
            Object account = this.account();
            Helpers.addElementToObject(account, "total", this.safeString(balance, "balance"));
            Helpers.addElementToObject(result, code, account);
        }
        return this.safeBalance(result);
    }

    /**
     * @method
     * @name ascendex#fetchBalance
     * @description query for balance and get the amount of funds available for trading or funds locked in orders
     * @see https://ascendex.github.io/ascendex-pro-api/#cash-account-balance
     * @see https://ascendex.github.io/ascendex-pro-api/#margin-account-balance
     * @see https://ascendex.github.io/ascendex-futures-pro-api-v2/#position
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.type] wallet type, 'spot', 'margin', or 'swap'
     * @param {string} [params.marginMode] 'cross' or undefined, for spot margin trading, value of 'isolated' is invalid
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            (this.loadAccounts()).join();
            Object marketType = null;
            Object marginMode = null;
            var marketTypeparametersVariable = this.handleMarketTypeAndParams("fetchBalance", null, parameters);
            marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
            var marginModeparametersVariable = this.handleMarginModeAndParams("fetchBalance", parameters);
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            Object isMargin = this.safeBool(parameters, "margin", false);
            Object isCross = Helpers.isEqual(marginMode, "cross");
            marketType = ((Helpers.isTrue((Helpers.isTrue(isMargin) || Helpers.isTrue(isCross))))) ? "margin" : marketType;
            parameters = this.omit(parameters, "margin");
            Object accountsByType = this.safeDict(this.options, "accountsByType", new java.util.HashMap<String, Object>() {{}});
            Object accountCategory = this.safeString(accountsByType, marketType, "cash");
            Object account = this.safeDict(this.accounts, 0, new java.util.HashMap<String, Object>() {{}});
            Object accountGroup = this.safeString(account, "id");
            Object request = new java.util.HashMap<String, Object>() {{
                put( "account-group", accountGroup );
            }};
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(marginMode, "isolated"))) && Helpers.isTrue((!Helpers.isEqual(marketType, "swap")))))
            {
                throw new BadRequest((String)Helpers.add(this.id, " does not supported isolated margin trading")) ;
            }
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(accountCategory, "cash"))) || Helpers.isTrue((Helpers.isEqual(accountCategory, "margin")))))
            {
                Helpers.addElementToObject(request, "account-category", accountCategory);
            }
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(marketType, "spot"))) || Helpers.isTrue((Helpers.isEqual(marketType, "margin")))))
            {
                response = (this.v1PrivateAccountCategoryGetBalance(this.extend(request, parameters))).join();
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
            {
                response = (this.v2PrivateAccountGroupGetFuturesPosition(this.extend(request, parameters))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchBalance() is not currently supported for "), marketType), " markets")) ;
            }
            //
            // cash
            //
            //     {
            //         "code": 0,
            //         "data": [
            //             {
            //                 "asset": "BCHSV",
            //                 "totalBalance": "64.298000048",
            //                 "availableBalance": "64.298000048",
            //             },
            //         ]
            //     }
            //
            // margin
            //
            //     {
            //         "code": 0,
            //         "data": [
            //             {
            //                 "asset": "BCHSV",
            //                 "totalBalance": "64.298000048",
            //                 "availableBalance": "64.298000048",
            //                 "borrowed": "0",
            //                 "interest": "0",
            //             },
            //         ]
            //     }
            //
            // swap
            //
            //     {
            //         "code": 0,
            //         "data": {
            //             "accountId": "fut2ODPhGiY71Pl4vtXnOZ00ssgD7QGn",
            //             "ac": "FUTURES",
            //             "collaterals": [
            //                 {"asset":"ADA","balance":"0.355803","referencePrice":"1.05095","discountFactor":"0.9"},
            //                 {"asset":"USDT","balance":"0.000014519","referencePrice":"1","discountFactor":"1"}
            //             ],
            //         }j
            //     }
            //
            if (Helpers.isTrue(Helpers.isEqual(marketType, "swap")))
            {
                return this.parseSwapBalance(response);
            } else if (Helpers.isTrue(Helpers.isEqual(marketType, "margin")))
            {
                return this.parseMarginBalance(response);
            } else
            {
                return this.parseBalance(response);
            }
        });

    }

    /**
     * @method
     * @name ascendex#fetchOrderBook
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
            }};
            Object response = (this.v1PublicGetDepth(this.extend(request, parameters))).join();
            //
            //     {
            //         "code":0,
            //         "data":{
            //             "m":"depth-snapshot",
            //             "symbol":"BTC-PERP",
            //             "data":{
            //                 "ts":1590223998202,
            //                 "seqnum":115444921,
            //                 "asks":[
            //                     ["9207.5","18.2383"],
            //                     ["9207.75","18.8235"],
            //                     ["9208","10.7873"],
            //                 ],
            //                 "bids":[
            //                     ["9207.25","0.4009"],
            //                     ["9207","0.003"],
            //                     ["9206.5","0.003"],
            //                 ]
            //             }
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object orderbook = this.safeDict(data, "data", new java.util.HashMap<String, Object>() {{}});
            Object timestamp = this.safeInteger(orderbook, "ts");
            Object result = this.parseOrderBook(orderbook, symbol, timestamp);
            Helpers.addElementToObject(result, "nonce", this.safeInteger(orderbook, "seqnum"));
            return result;
        });

    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol":"QTUM/BTC",
        //         "open":"0.00016537",
        //         "close":"0.00019077",
        //         "high":"0.000192",
        //         "low":"0.00016537",
        //         "volume":"846.6",
        //         "ask":["0.00018698","26.2"],
        //         "bid":["0.00018408","503.7"],
        //         "type":"spot"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = null;
        Object marketId = this.safeString(ticker, "symbol");
        Object type = this.safeString(ticker, "type");
        Object delimiter = ((Helpers.isTrue((Helpers.isEqual(type, "spot"))))) ? "/" : null;
        Object symbol = this.safeSymbol(marketId, market, delimiter);
        Object close = this.safeString(ticker, "close");
        Object bid = this.safeList(ticker, "bid", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object ask = this.safeList(ticker, "ask", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object open = this.safeString(ticker, "open");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", null );
            put( "high", AscendexCore.this.safeString(ticker, "high") );
            put( "low", AscendexCore.this.safeString(ticker, "low") );
            put( "bid", AscendexCore.this.safeString(bid, 0) );
            put( "bidVolume", AscendexCore.this.safeString(bid, 1) );
            put( "ask", AscendexCore.this.safeString(ask, 0) );
            put( "askVolume", AscendexCore.this.safeString(ask, 1) );
            put( "vwap", null );
            put( "open", open );
            put( "close", close );
            put( "last", close );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", AscendexCore.this.safeString(ticker, "volume") );
            put( "quoteVolume", null );
            put( "info", ticker );
        }}, market);
    }

