    /**
     * @method
     * @name ascendex#fetchOHLCV
     * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
     * @param {string} symbol unified symbol of the market to fetch OHLCV data for
     * @param {string} timeframe the length of time each candle represents
     * @param {int} [since] timestamp in ms of the earliest candle to fetch
     * @param {int} [limit] the maximum amount of candles to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {int} [params.until] timestamp in ms of the latest candle to fetch
     * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOHLCV(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object timeframe = Helpers.getArg(optionalArgs, 0, "1m");
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", Helpers.GetValue(market, "id") );
                put( "interval", AscendexCore.this.safeString(AscendexCore.this.timeframes, timeframe, timeframe) );
            }};
            // if since and limit are not specified
            // the exchange will return just 1 last candle by default
            Object duration = this.parseTimeframe(timeframe);
            Object options = this.safeDict(this.options, "fetchOHLCV", new java.util.HashMap<String, Object>() {{}});
            Object defaultLimit = this.safeInteger(options, "limit", 500);
            Object until = this.safeInteger(parameters, "until");
            if (Helpers.isTrue(!Helpers.isEqual(since, null)))
            {
                Helpers.addElementToObject(request, "from", since);
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = defaultLimit;
                } else
                {
                    limit = Helpers.mathMin(limit, defaultLimit);
                }
                Object toWithLimit = this.sum(since, Helpers.multiply(Helpers.multiply(limit, duration), 1000), 1);
                if (Helpers.isTrue(!Helpers.isEqual(until, null)))
                {
                    Helpers.addElementToObject(request, "to", Helpers.mathMin(toWithLimit, Helpers.add(until, 1)));
                } else
                {
                    Helpers.addElementToObject(request, "to", toWithLimit);
                }
            } else if (Helpers.isTrue(!Helpers.isEqual(until, null)))
            {
                Helpers.addElementToObject(request, "to", Helpers.add(until, 1));
                if (Helpers.isTrue(Helpers.isEqual(limit, null)))
                {
                    limit = defaultLimit;
                } else
                {
                    limit = Helpers.mathMin(limit, defaultLimit);
                }
                Helpers.addElementToObject(request, "from", Helpers.subtract(until, (Helpers.multiply(Helpers.multiply(limit, duration), 1000))));
            } else if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "n", limit); // max 500
            }
            parameters = this.omit(parameters, "until");
            Object response = (this.v1PublicGetBarhist(this.extend(request, parameters))).join();
            //
            //     {
            //         "code":0,
            //         "data":[
            //             {
            //                 "m":"bar",
            //                 "s":"BTC/USDT",
            //                 "data":{
            //                     "i":"1",
            //                     "ts":1590228000000,
            //                     "o":"9139.59",
            //                     "c":"9131.94",
            //                     "h":"9139.99",
            //                     "l":"9121.71",
            //                     "v":"25.20648"
            //                 }
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOHLCVs(data, market, timeframe, since, limit);
        });

    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // public fetchTrades
        //
        //     {
        //         "p":"9128.5", // price
        //         "q":"0.0030", // quantity
        //         "ts":1590229002385, // timestamp
        //         "bm":false, // if true, the buyer is the market maker, we only use this field to "define the side" of a public trade
        //         "seqnum":180143985289898554
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(trade, "ts");
        Object priceString = this.safeString2(trade, "price", "p");
        Object amountString = this.safeString(trade, "q");
        Object buyerIsMaker = this.safeBool(trade, "bm", false);
        Object side = ((Helpers.isTrue(buyerIsMaker))) ? "sell" : "buy";
        market = this.safeMarket(null, market);
        final Object finalMarket = market;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", AscendexCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "id", null );
            put( "order", null );
            put( "type", null );
            put( "takerOrMaker", null );
            put( "side", side );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", null );
        }}, market);
    }

