    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder
        //
        //     {
        //         "id": "16e607e2b83a8bXHbAwwoqDo55c166fa",
        //         "orderId": "16e85b4d9b9a8bXHbAwwoqDoc3d66830",
        //         "orderType": "Market",
        //         "symbol": "BTC/USDT",
        //         "timestamp": 1573576916201
        //     }
        //
        //  & linear (fetchClosedOrders)
        //
        //     {
        //         "ac": "FUTURES",
        //         "accountId": "fut2ODPhGiY71Pl4vtXnOZ00ssgD7QGn",
        //         "time": 1640819389454,
        //         "orderId": "a17e0874ecbdU0711043490bbtcpDU5X",
        //         "seqNum": -1,
        //         "orderType": "Limit",
        //         "execInst": "NULL_VAL", // NULL_VAL, ReduceOnly , ...
        //         "side": "Buy",
        //         "symbol": "BTC-PERP",
        //         "price": "30000",
        //         "orderQty": "0.002",
        //         "stopPrice": "0",
        //         "stopBy": "ref-px",
        //         "status": "Ack",
        //         "lastExecTime": 1640819389454,
        //         "lastQty": "0",
        //         "lastPx": "0",
        //         "avgFilledPx": "0",
        //         "cumFilledQty": "0",
        //         "fee": "0",
        //         "cumFee": "0",
        //         "feeAsset": "",
        //         "errorCode": "",
        //         "posStopLossPrice": "0",
        //         "posStopLossTrigger": "market",
        //         "posTakeProfitPrice": "0",
        //         "posTakeProfitTrigger": "market",
        //         "liquidityInd": "n"
        //      }
        //
        // fetchOrder, fetchOpenOrders, fetchClosedOrders
        //
        //     {
        //         "symbol":       "BTC/USDT",
        //         "price":        "8131.22",
        //         "orderQty":     "0.00082",
        //         "orderType":    "Market",
        //         "avgPx":        "7392.02",
        //         "cumFee":       "0.005152238",
        //         "cumFilledQty": "0.00082",
        //         "errorCode":    "",
        //         "feeAsset":     "USDT",
        //         "lastExecTime": 1575953151764,
        //         "orderId":      "a16eee20b6750866943712zWEDdAjt3",
        //         "seqNum":       2623469,
        //         "side":         "Buy",
        //         "status":       "Filled",
        //         "stopPrice":    "",
        //         "execInst":     "NULL_VAL" // "Post" (for postOnly orders), "reduceOnly" (for reduceOnly orders)
        //     }
        //
        //     {
        //         "orderId": "a173ad938fc3U22666567717788c3b66",   // orderId
        //         "seqNum": 18777366360,                           // sequence number
        //         "accountId": "cshwSjbpPjSwHmxPdz2CPQVU9mnbzPpt", // accountId
        //         "symbol": "BTC/USDT",                            // symbol
        //         "orderType": "Limit",                            // order type (Limit/Market/StopMarket/StopLimit)
        //         "side": "Sell",                                  // order side (Buy/Sell)
        //         "price": "11346.77",                             // order price
        //         "stopPrice": "0",                                // stop price (0 by default)
        //         "orderQty": "0.01",                              // order quantity (in base asset)
        //         "status": "Canceled",                            // order status (Filled/Canceled/Rejected)
        //         "createTime": 1596344995793,                     // order creation time
        //         "lastExecTime": 1596344996053,                   // last execution time
        //         "avgFillPrice": "11346.77",                      // average filled price
        //         "fillQty": "0.01",                               // filled quantity (in base asset)
        //         "fee": "-0.004992579",                           // cummulative fee. if negative, this value is the commission charged; if possitive, this value is the rebate received.
        //         "feeAsset": "USDT"                               // fee asset
        //     }
        //
        //     {
        //         "ac": "FUTURES",
        //         "accountId": "testabcdefg",
        //         "avgPx": "0",
        //         "cumFee": "0",
        //         "cumQty": "0",
        //         "errorCode": "NULL_VAL",
        //         "execInst": "NULL_VAL",
        //         "feeAsset": "USDT",
        //         "lastExecTime": 1584072844085,
        //         "orderId": "r170d21956dd5450276356bbtcpKa74",
        //         "orderQty": "1.1499",
        //         "orderType": "Limit",
        //         "price": "4000",
        //         "sendingTime": 1584072841033,
        //         "seqNum": 24105338,
        //         "side": "Buy",
        //         "status": "Canceled",
        //         "stopPrice": "",
        //         "symbol": "BTC-PERP"
        //     },
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object marketId = this.safeString(order, "symbol");
        Object symbol = this.safeSymbol(marketId, market, "/");
        Object timestamp = this.safeIntegerN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("timestamp", "sendingTime", "time")));
        Object lastTradeTimestamp = this.safeInteger(order, "lastExecTime");
        if (Helpers.isTrue(Helpers.isEqual(timestamp, null)))
        {
            timestamp = lastTradeTimestamp;
        }
        Object price = this.safeString(order, "price");
        Object amount = this.safeString(order, "orderQty");
        Object average = this.safeString2(order, "avgPx", "avgFilledPx");
        Object filled = this.safeStringN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("cumFilledQty", "cumQty", "fillQty")));
        Object id = this.safeString(order, "orderId");
        Object clientOrderId = this.safeString(order, "id");
        if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
        {
            if (Helpers.isTrue(Helpers.isLessThan(((String)clientOrderId).length(), 1)))
            {
                clientOrderId = null;
            }
        }
        Object rawTypeLower = this.safeStringLower(order, "orderType");
        Object type = rawTypeLower;
        if (Helpers.isTrue(!Helpers.isEqual(rawTypeLower, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(rawTypeLower, "stoplimit")))
            {
                type = "limit";
            }
            if (Helpers.isTrue(Helpers.isEqual(rawTypeLower, "stopmarket")))
            {
                type = "market";
            }
        }
        Object side = this.safeStringLower(order, "side");
        Object feeCost = this.safeNumber2(order, "cumFee", "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            Object feeCurrencyId = this.safeString(order, "feeAsset");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", feeCurrencyCode );
            }};
        }
        Object triggerPrice = this.omitZero(((String)this.safeString(order, "stopPrice")));
        Object reduceOnly = null;
        Object execInst = this.safeStringLower(order, "execInst");
        if (Helpers.isTrue(Helpers.isEqual(execInst, "reduceonly")))
        {
            reduceOnly = true;
        }
        Object postOnly = null;
        if (Helpers.isTrue(Helpers.isEqual(execInst, "post")))
        {
            postOnly = true;
        }
        final Object finalClientOrderId = clientOrderId;
        final Object finalTimestamp = timestamp;
        final Object finalType = type;
        final Object finalPostOnly = postOnly;
        final Object finalReduceOnly = reduceOnly;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", finalClientOrderId );
            put( "timestamp", finalTimestamp );
            put( "datetime", AscendexCore.this.iso8601(finalTimestamp) );
            put( "lastTradeTimestamp", lastTradeTimestamp );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", null );
            put( "postOnly", finalPostOnly );
            put( "reduceOnly", finalReduceOnly );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", triggerPrice );
            put( "amount", amount );
            put( "cost", null );
            put( "average", average );
            put( "filled", filled );
            put( "remaining", null );
            put( "status", status );
            put( "fee", finalFee );
            put( "trades", null );
        }}, market);
    }

