    public Object createOrderRequest(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {
        /**
        * @method
        * @ignore
        * @name ascendex#createOrderRequest
        * @description helper function to build request
        * @param {string} symbol unified symbol of the market to create an order in
        * @param {string} type 'market' or 'limit'
        * @param {string} side 'buy' or 'sell'
        * @param {float} amount how much you want to trade in units of the base currency
        * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
        * @param {object} [params] extra parameters specific to the exchange API endpoint
        * @param {string} [params.timeInForce] "GTC", "IOC", "FOK", or "PO"
        * @param {bool} [params.postOnly] true or false
        * @param {float} [params.triggerPrice] the price at which a trigger order is triggered at
        * @returns {object} request to be sent to the exchange
        */
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object market = this.market(symbol);
        Object marginMode = null;
        Object marketType = null;
        var marginModeparametersVariable = this.handleMarginModeAndParams("createOrderRequest", parameters);
        marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
        parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
        var marketTypeparametersVariable = this.handleMarketTypeAndParams("createOrderRequest", market, parameters);
        marketType = ((java.util.List<Object>) marketTypeparametersVariable).get(0);
        parameters = ((java.util.List<Object>) marketTypeparametersVariable).get(1);
        Object accountsByType = this.safeDict(this.options, "accountsByType", new java.util.HashMap<String, Object>() {{}});
        Object accountCategory = this.safeString(accountsByType, marketType, "cash");
        if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
        {
            accountCategory = "margin";
        }
        Object account = this.safeDict(this.accounts, 0, new java.util.HashMap<String, Object>() {{}});
        Object accountGroup = this.safeString(account, "id");
        Object clientOrderId = this.safeString2(parameters, "clientOrderId", "id");
        final Object finalAccountCategory = accountCategory;
        final Object finalType = type;
        Object request = new java.util.HashMap<String, Object>() {{
            put( "account-group", accountGroup );
            put( "account-category", finalAccountCategory );
            put( "symbol", Helpers.GetValue(market, "id") );
            put( "time", AscendexCore.this.milliseconds() );
            put( "orderQty", AscendexCore.this.amountToPrecision(symbol, amount) );
            put( "orderType", finalType );
            put( "side", side );
        }};
        Object isMarketOrder = (Helpers.isTrue((Helpers.isEqual(type, "market"))) || Helpers.isTrue((Helpers.isEqual(type, "stop_market"))));
        Object isLimitOrder = (Helpers.isTrue((Helpers.isEqual(type, "limit"))) || Helpers.isTrue((Helpers.isEqual(type, "stop_limit"))));
        Object timeInForce = this.safeString(parameters, "timeInForce");
        Object postOnly = this.isPostOnly(isMarketOrder, false, parameters);
        Object reduceOnly = this.safeBool(parameters, "reduceOnly", false);
        Object triggerPrice = this.safeString2(parameters, "triggerPrice", "stopPrice");
        if (Helpers.isTrue(isLimitOrder))
        {
            Helpers.addElementToObject(request, "orderPrice", this.priceToPrecision(symbol, price));
        }
        if (Helpers.isTrue(Helpers.isEqual(timeInForce, "IOC")))
        {
            Helpers.addElementToObject(request, "timeInForce", "IOC");
        }
        if (Helpers.isTrue(Helpers.isEqual(timeInForce, "FOK")))
        {
            Helpers.addElementToObject(request, "timeInForce", "FOK");
        }
        if (Helpers.isTrue(postOnly))
        {
            Helpers.addElementToObject(request, "postOnly", true);
        }
        if (Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)))
        {
            Helpers.addElementToObject(request, "stopPrice", this.priceToPrecision(symbol, triggerPrice));
            if (Helpers.isTrue(isLimitOrder))
            {
                Helpers.addElementToObject(request, "orderType", "stop_limit");
            } else if (Helpers.isTrue(isMarketOrder))
            {
                Helpers.addElementToObject(request, "orderType", "stop_market");
            }
        }
        if (Helpers.isTrue(!Helpers.isEqual(clientOrderId, null)))
        {
            Helpers.addElementToObject(request, "id", clientOrderId);
        }
        if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
        {
            if (Helpers.isTrue(!Helpers.isEqual(accountCategory, null)))
            {
                Helpers.addElementToObject(request, "category", accountCategory);
            }
        } else
        {
            Helpers.addElementToObject(request, "account-category", accountCategory);
            if (Helpers.isTrue(reduceOnly))
            {
                Helpers.addElementToObject(request, "execInst", "ReduceOnly");
            }
            if (Helpers.isTrue(postOnly))
            {
                Helpers.addElementToObject(request, "execInst", "Post");
            }
        }
        parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("reduceOnly", "triggerPrice")));
        return this.extend(request, parameters);
    }

