    /**
     * @method
     * @name ascendex#createOrders
     * @description create a list of trade orders
     * @see https://ascendex.github.io/ascendex-pro-api/#place-batch-orders
     * @see https://ascendex.github.io/ascendex-futures-pro-api-v2/#place-batch-orders
     * @param {Array} orders list of orders to create, each object should contain the parameters required by createOrder, namely symbol, type, side, amount, price and params
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.timeInForce] "GTC", "IOC", "FOK", or "PO"
     * @param {bool} [params.postOnly] true or false
     * @param {float} [params.triggerPrice] the price at which a trigger order is triggered at
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrders(Object orders, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            (this.loadAccounts()).join();
            Object ordersRequests = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            Object symbol = null;
            Object marginMode = null;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(orders)); i++)
            {
                Object rawOrder = Helpers.GetValue(orders, i);
                Object marketId = this.safeString(rawOrder, "symbol");
                if (Helpers.isTrue(Helpers.isEqual(symbol, null)))
                {
                    symbol = marketId;
                } else
                {
                    if (Helpers.isTrue(!Helpers.isEqual(symbol, marketId)))
                    {
                        throw new BadRequest((String)Helpers.add(this.id, " createOrders() requires all orders to have the same symbol")) ;
                    }
                }
                Object type = this.safeString(rawOrder, "type");
                Object side = this.safeString(rawOrder, "side");
                Object amount = this.safeNumber(rawOrder, "amount");
                Object price = this.safeNumber(rawOrder, "price");
                Object orderParams = this.safeDict(rawOrder, "params", new java.util.HashMap<String, Object>() {{}});
                Object marginResult = this.handleMarginModeAndParams("createOrders", orderParams);
                Object currentMarginMode = Helpers.GetValue(marginResult, 0);
                if (Helpers.isTrue(!Helpers.isEqual(currentMarginMode, null)))
                {
                    if (Helpers.isTrue(Helpers.isEqual(marginMode, null)))
                    {
                        marginMode = currentMarginMode;
                    } else
                    {
                        if (Helpers.isTrue(!Helpers.isEqual(marginMode, currentMarginMode)))
                        {
                            throw new BadRequest((String)Helpers.add(this.id, " createOrders() requires all orders to have the same margin mode (isolated or cross)")) ;
                        }
                    }
                }
                Object orderRequest = this.createOrderRequest(((String)marketId), ((String)type), side, amount, price, orderParams);
                ((java.util.List<Object>)ordersRequests).add(orderRequest);
            }
            Object market = this.market(((String)symbol));
            Object accountsByType = this.safeDict(this.options, "accountsByType", new java.util.HashMap<String, Object>() {{}});
            Object accountCategory = this.safeString(accountsByType, Helpers.GetValue(market, "type"), "cash");
            if (Helpers.isTrue(!Helpers.isEqual(marginMode, null)))
            {
                accountCategory = "margin";
            }
            Object account = this.safeDict(this.accounts, 0, new java.util.HashMap<String, Object>() {{}});
            Object accountGroup = this.safeString(account, "id");
            Object request = new java.util.HashMap<String, Object>() {{}};
            Object response = null;
            if (Helpers.isTrue(Helpers.GetValue(market, "swap")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " createOrders() is not currently supported for swap markets on ascendex")) ;
            } else
            {
                Helpers.addElementToObject(request, "account-group", accountGroup);
                Helpers.addElementToObject(request, "account-category", accountCategory);
                Helpers.addElementToObject(request, "orders", ordersRequests);
                response = (this.v1PrivateAccountCategoryPostOrderBatch(request)).join();
            }
            //
            // spot
            //
            //     {
            //         "code": 0,
            //         "data": {
            //             "accountId": "cshdAKBO43TKIh2kJtq7FVVb42KIePyS",
            //             "ac": "CASH",
            //             "action": "batch-place-order",
            //             "status": "Ack",
            //             "info": [
            //                 {
            //                     "symbol": "BTC/USDT",
            //                     "orderType": "Limit",
            //                     "timestamp": 1699326589344,
            //                     "id": "",
            //                     "orderId": "a18ba7c1f6efU0711043490p3HvjjN5x"
            //                 }
            //             ]
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object info = this.safeList(data, "info", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseOrders(info, market);
        });

    }

