            Object accountCategory = this.safeString(accountsByType, type, "cash");
            final Object finalAccountCategory = accountCategory;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "account-group", accountGroup );
                put( "account-category", finalAccountCategory );
            }};
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(type, "spot"))) || Helpers.isTrue((Helpers.isEqual(type, "margin")))))
            {
                response = (this.v1PrivateAccountCategoryGetOrderOpen(this.extend(request, query))).join();
            } else if (Helpers.isTrue(Helpers.isEqual(type, "swap")))
            {
                Helpers.addElementToObject(request, "account-category", accountCategory);
                response = (this.v2PrivateAccountGroupGetFuturesOrderOpen(this.extend(request, query))).join();
            } else
            {
                throw new NotSupported((String)Helpers.add(Helpers.add(Helpers.add(this.id, " fetchOpenOrders() is not currently supported for "), type), " markets")) ;
            }
            //
            // AccountCategoryGetOrderOpen
            //
            //     {
            //         "ac": "CASH",
            //         "accountId": "cshQtyfq8XLAA9kcf19h8bXHbAwwoqDo",
            //         "code": 0,
            //         "data": [
            //             {
            //                 "avgPx": "0",        // Average filled price of the order
            //                 "cumFee": "0",       // cumulative fee paid for this order
            //                 "cumFilledQty": "0", // cumulative filled quantity
            //                 "errorCode": "",     // error code; could be empty
            //                 "feeAsset": "USDT",  // fee asset
            //                 "lastExecTime": 1576019723550, //  The last execution time of the order
            //                 "orderId": "s16ef21882ea0866943712034f36d83", // server provided orderId
            //                 "orderQty": "0.0083",  // order quantity
            //                 "orderType": "Limit",  // order type
            //                 "price": "7105",       // order price
            //                 "seqNum": 8193258,     // sequence number
            //                 "side": "Buy",         // order side
            //                 "status": "New",       // order status on matching engine
            //                 "stopPrice": "",       // only available for stop market and stop limit orders; otherwise empty
            //                 "symbol": "BTC/USDT",
            //                 "execInst": "NULL_VAL" // execution instruction
            //             },
            //         ]
