    public Object parseDepositAddress(Object depositAddress, Object... optionalArgs)
    {
        //
        //     {
        //         "address": "0xe7c70b4e73b6b450ee46c3b5c0f5fb127ca55722",
        //         "destTag": "",
        //         "tagType": "",
        //         "tagId": "",
        //         "chainName": "ERC20",
        //         "numConfirmations": 20,
        //         "withdrawalFee": 1,
        //         "nativeScale": 4,
        //         "tips": []
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object address = this.safeString(depositAddress, "address");
        Object tagId = this.safeString(depositAddress, "tagId");
        Object tag = this.safeString(depositAddress, ((String)tagId));
        this.checkAddress(address);
        Object code = ((Helpers.isTrue((Helpers.isEqual(currency, null))))) ? null : Helpers.GetValue(currency, "code");
        Object chainName = this.safeString(depositAddress, "blockchain");
        Object network = this.networkIdToCode(chainName, code);
        return new java.util.HashMap<String, Object>() {{
            put( "info", depositAddress );
            put( "currency", code );
            put( "network", network );
            put( "address", address );
            put( "tag", tag );
        }};
    }

    /**
     * @method
     * @name ascendex#fetchDepositAddress
     * @description fetch the deposit address for a currency associated with this account
     * @see https://ascendex.github.io/ascendex-pro-api/#query-deposit-addresses
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.network] unified network code for deposit chain
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object currency = this.currency(code);
            Object networkCode = this.safeString2(parameters, "network", "chainName");
            Object networkId = this.networkCodeToId(((String)networkCode), Helpers.GetValue(currency, "code"));
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("chainName")));
            final Object finalNetworkId = networkId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "asset", Helpers.GetValue(currency, "id") );
                put( "blockchain", finalNetworkId );
            }};
            Object response = (this.v1PrivateGetWalletDepositAddress(this.extend(request, parameters))).join();
            //
            //     {
            //         "code":0,
            //         "data":{
            //             "asset":"USDT",
            //             "assetName":"Tether",
            //             "address":[
            //                 {
            //                     "address":"1N22odLHXnLPCjC8kwBJPTayarr9RtPod6",
            //                     "destTag":"",
            //                     "tagType":"",
            //                     "tagId":"",
            //                     "chainName":"Omni",
            //                     "numConfirmations":3,
            //                     "withdrawalFee":4.7,
            //                     "nativeScale":4,
            //                     "tips":[]
            //                 },
            //                 {
            //                     "address":"0xe7c70b4e73b6b450ee46c3b5c0f5fb127ca55722",
            //                     "destTag":"",
            //                     "tagType":"",
            //                     "tagId":"",
            //                     "chainName":"ERC20",
            //                     "numConfirmations":20,
            //                     "withdrawalFee":1.0,
            //                     "nativeScale":4,
            //                     "tips":[]
            //                 }
            //             ]
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object addresses = this.safeList(data, "address", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object numAddresses = Helpers.getArrayLength(addresses);
            Object address = null;
            if (Helpers.isTrue(Helpers.isGreaterThan(numAddresses, 1)))
            {
                Object addressesByChainName = this.indexBy(addresses, "chainName");
                if (Helpers.isTrue(Helpers.isEqual(networkId, null)))
                {
                    Object chainNames = Helpers.objectKeys(addressesByChainName);
                    Object chains = String.join((String)", ", (java.util.List<String>)chainNames);
                    throw new ArgumentsRequired((String)Helpers.add(Helpers.add(this.id, " fetchDepositAddress() returned more than one address, a chainName parameter is required, one of "), chains)) ;
                }
                address = this.safeDict(addressesByChainName, networkId, new java.util.HashMap<String, Object>() {{}});
            } else
            {
                // first address
                address = this.safeDict(addresses, 0, new java.util.HashMap<String, Object>() {{}});
            }
            Object result = this.parseDepositAddress(address, currency);
            return this.extend(result, new java.util.HashMap<String, Object>() {{
                put( "info", response );
            }});
        });

    }

