    public Object parseTransactionStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "reviewing", "pending" );
            put( "pending", "pending" );
            put( "confirmed", "ok" );
            put( "rejected", "rejected" );
        }};
        return this.safeString(statuses, ((String)status), status);
    }

    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        //     {
        //         "requestId": "wuzd1Ojsqtz4bCA3UXwtUnnJDmU8PiyB",
        //         "time": 1591606166000,
        //         "asset": "USDT",
        //         "transactionType": "deposit",
        //         "amount": "25",
        //         "commission": "0",
        //         "networkTransactionId": "0xbc4eabdce92f14dbcc01d799a5f8ca1f02f4a3a804b6350ea202be4d3c738fce",
        //         "status": "pending",
        //         "numConfirmed": 8,
        //         "numConfirmations": 20,
        //         "destAddress": {
        //             "address": "0xe7c70b4e73b6b450ee46c3b5c0f5fb127ca55722",
        //             "destTag": "..." // for currencies that have it
        //         }
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object destAddress = this.safeDict(transaction, "destAddress", new java.util.HashMap<String, Object>() {{}});
        Object address = this.safeString(destAddress, "address");
        Object tag = this.safeString(destAddress, "destTag");
        Object timestamp = this.safeInteger(transaction, "time");
        Object currencyId = this.safeString(transaction, "asset");
        Object amountString = this.safeString(transaction, "amount");
        Object feeCostString = this.safeString(transaction, "commission");
        amountString = Precise.stringSub(amountString, feeCostString);
        Object code = this.safeCurrencyCode(currencyId, currency);
        final Object finalAmountString = amountString;
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", AscendexCore.this.safeString(transaction, "requestId") );
            put( "txid", AscendexCore.this.safeString(transaction, "networkTransactionId") );
            put( "type", AscendexCore.this.safeString(transaction, "transactionType") );
            put( "currency", code );
            put( "network", null );
            put( "amount", AscendexCore.this.parseNumber(finalAmountString) );
            put( "status", AscendexCore.this.parseTransactionStatus(AscendexCore.this.safeString(transaction, "status")) );
            put( "timestamp", timestamp );
            put( "datetime", AscendexCore.this.iso8601(timestamp) );
            put( "address", address );
            put( "addressFrom", null );
            put( "addressTo", address );
            put( "tag", tag );
            put( "tagFrom", null );
            put( "tagTo", tag );
            put( "updated", null );
            put( "comment", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", code );
                put( "cost", AscendexCore.this.parseNumber(feeCostString) );
                put( "rate", null );
            }} );
            put( "internal", false );
        }};
    }

