    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "BTC-PERP",
        //         "side": "LONG",
        //         "position": "0.0001",
        //         "referenceCost": "-3.12277254",
        //         "unrealizedPnl": "-0.001700233",
        //         "realizedPnl": "0",
        //         "avgOpenPrice": "31209",
        //         "marginType": "isolated",
        //         "isolatedMargin": "1.654972977",
        //         "leverage": "2",
        //         "takeProfitPrice": "0",
        //         "takeProfitTrigger": "market",
        //         "stopLossPrice": "0",
        //         "stopLossTrigger": "market",
        //         "buyOpenOrderNotional": "0",
        //         "sellOpenOrderNotional": "0",
        //         "markPrice": "31210.723063672",
        //         "indexPrice": "31223.148857925"
        //     },
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(position, "symbol");
        market = this.safeMarket(marketId, market);
        Object notional = this.safeString(position, "buyOpenOrderNotional");
        if (Helpers.isTrue(Precise.stringEq(notional, "0")))
        {
            notional = this.safeString(position, "sellOpenOrderNotional");
        }
        Object marginType = this.safeString(position, "marginType");
        Object marginMode = ((Helpers.isTrue((Helpers.isEqual(marginType, "crossed"))))) ? "cross" : "isolated";
        Object collateral = null;
        if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
        {
            collateral = this.safeString(position, "isolatedMargin");
        }
        final Object finalMarket = market;
        final Object finalNotional = notional;
        final Object finalMarginMode = marginMode;
        final Object finalCollateral = collateral;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "notional", AscendexCore.this.parseNumber(finalNotional) );
            put( "marginMode", finalMarginMode );
            put( "liquidationPrice", null );
            put( "entryPrice", AscendexCore.this.safeNumber(position, "avgOpenPrice") );
            put( "unrealizedPnl", AscendexCore.this.safeNumber(position, "unrealizedPnl") );
            put( "percentage", null );
            put( "contracts", AscendexCore.this.safeNumber(position, "position") );
            put( "contractSize", AscendexCore.this.safeNumber(finalMarket, "contractSize") );
            put( "markPrice", AscendexCore.this.safeNumber(position, "markPrice") );
            put( "lastPrice", null );
            put( "side", AscendexCore.this.safeStringLower(position, "side") );
            put( "hedged", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "lastUpdateTimestamp", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "collateral", finalCollateral );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "leverage", AscendexCore.this.safeInteger(position, "leverage") );
            put( "marginRatio", null );
            put( "stopLossPrice", AscendexCore.this.safeNumber(position, "stopLossPrice") );
            put( "takeProfitPrice", AscendexCore.this.safeNumber(position, "takeProfitPrice") );
        }});
    }

