    public Object parseMarketLeverageTiers(Object info, Object... optionalArgs)
    {
        /**
        * @param {object} info Exchange market response for 1 market
        * @param {object} market CCXT market
        */
        //
        //    {
        //        "symbol":"BTC-PERP",
        //        "status":"Normal",
        //        "displayName":"BTCUSDT",
        //        "settlementAsset":"USDT",
        //        "underlying":"BTC/USDT",
        //        "tradingStartTime":1579701600000,
        //        "priceFilter":{"minPrice":"1","maxPrice":"1000000","tickSize":"1"},
        //        "lotSizeFilter":{"minQty":"0.0001","maxQty":"1000000000","lotSize":"0.0001"},
        //        "commissionType":"Quote",
        //        "commissionReserveRate":"0.001",
        //        "marketOrderPriceMarkup":"0.03",
        //        "marginRequirements":[
        //            {"positionNotionalLowerBound":"0","positionNotionalUpperBound":"50000","initialMarginRate":"0.01","maintenanceMarginRate":"0.006"},
        //            {"positionNotionalLowerBound":"50000","positionNotionalUpperBound":"200000","initialMarginRate":"0.02","maintenanceMarginRate":"0.012"},
        //            {"positionNotionalLowerBound":"200000","positionNotionalUpperBound":"2000000","initialMarginRate":"0.04","maintenanceMarginRate":"0.024"},
        //            {"positionNotionalLowerBound":"2000000","positionNotionalUpperBound":"20000000","initialMarginRate":"0.1","maintenanceMarginRate":"0.06"},
        //            {"positionNotionalLowerBound":"20000000","positionNotionalUpperBound":"40000000","initialMarginRate":"0.2","maintenanceMarginRate":"0.12"},
        //            {"positionNotionalLowerBound":"40000000","positionNotionalUpperBound":"1000000000","initialMarginRate":"0.333333","maintenanceMarginRate":"0.2"}
        //        ]
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marginRequirements = this.safeList(info, "marginRequirements", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object marketId = this.safeString(info, "symbol");
        market = this.safeMarket(marketId, market);
        Object tiers = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marginRequirements)); i++)
        {
            Object tier = Helpers.GetValue(marginRequirements, i);
            Object initialMarginRate = this.safeString(tier, "initialMarginRate");
final Object finalI = i;
            final Object finalMarket = market;
                        ((java.util.List<Object>)tiers).add(new java.util.HashMap<String, Object>() {{
                put( "tier", AscendexCore.this.sum(finalI, 1) );
                put( "symbol", AscendexCore.this.safeSymbol(marketId, finalMarket, null, "contract") );
                put( "currency", Helpers.GetValue(finalMarket, "quote") );
                put( "minNotional", AscendexCore.this.safeNumber(tier, "positionNotionalLowerBound") );
                put( "maxNotional", AscendexCore.this.safeNumber(tier, "positionNotionalUpperBound") );
                put( "maintenanceMarginRate", AscendexCore.this.safeNumber(tier, "maintenanceMarginRate") );
                put( "maxLeverage", AscendexCore.this.parseNumber(Precise.stringDiv("1", initialMarginRate)) );
                put( "info", tier );
            }});
        }
        return tiers;
    }

    public Object parseDepositWithdrawFee(Object fee, Object... optionalArgs)
    {
        //
        // {
        //     "assetCode":      "USDT",
        //     "assetName":      "Tether",
        //     "precisionScale":  9,
        //     "nativeScale":     4,
        //     "blockChain": [
        //         {
        //             "chainName":        "Omni",
        //             "withdrawFee":      "30.0",
        //             "allowDeposit":      true,
        //             "allowWithdraw":     true,
        //             "minDepositAmt":    "0.0",
        //             "minWithdrawal":    "50.0",
        //             "numConfirmations":  3
        //         },
        //     ]
        // }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object blockChains = this.safeList(fee, "blockChain", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object blockChainsLength = Helpers.getArrayLength(blockChains);
        Object result = new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "withdraw", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "deposit", new java.util.HashMap<String, Object>() {{
                put( "fee", null );
                put( "percentage", null );
            }} );
            put( "networks", new java.util.HashMap<String, Object>() {{}} );
        }};
        for (var i = 0; Helpers.isLessThan(i, blockChainsLength); i++)
        {
            Object blockChain = Helpers.GetValue(blockChains, i);
            Object networkId = this.safeString(blockChain, "chainName");
            Object currencyCode = this.safeString(currency, "code");
            Object networkCode = this.networkIdToCode(networkId, currencyCode);
            Helpers.addElementToObject(Helpers.GetValue(result, "networks"), networkCode, new java.util.HashMap<String, Object>() {{
    put( "deposit", new java.util.HashMap<String, Object>() {{
        put( "fee", null );
        put( "percentage", null );
    }} );
    put( "withdraw", new java.util.HashMap<String, Object>() {{
        put( "fee", AscendexCore.this.safeNumber(blockChain, "withdrawFee") );
        put( "percentage", false );
    }} );
}});
            if (Helpers.isTrue(Helpers.isEqual(blockChainsLength, 1)))
            {
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "fee", this.safeNumber(blockChain, "withdrawFee"));
                Helpers.addElementToObject(Helpers.GetValue(result, "withdraw"), "percentage", false);
            }
        }
        return result;
    }

