    /**
     * @method
     * @name ascendex#transfer
     * @description transfer currency internally between wallets on the same account
     * @param {string} code unified currency codeåå
     * @param {float} amount amount to transfer
     * @param {string} fromAccount account to transfer from
     * @param {string} toAccount account to transfer to
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transfer structure]{@link https://docs.ccxt.com/?id=transfer-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> transfer(Object code, Object amount, Object fromAccount, Object toAccount, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            (this.loadAccounts()).join();
            Object account = this.safeDict(this.accounts, 0, new java.util.HashMap<String, Object>() {{}});
            Object accountGroup = this.safeString(account, "id");
            Object currency = this.currency(code);
            Object accountsByType = this.safeDict(this.options, "accountsByType", new java.util.HashMap<String, Object>() {{}});
            Object fromId = this.safeString(accountsByType, fromAccount, fromAccount);
            Object toId = this.safeString(accountsByType, toAccount, toAccount);
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(fromId, "cash")) && Helpers.isTrue(!Helpers.isEqual(toId, "cash"))))
            {
                throw new ExchangeError((String)Helpers.add(this.id, " transfer() only supports direct balance transfer between spot and swap, spot and margin")) ;
            }
            final Object finalFromId = fromId;
            final Object finalToId = toId;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "account-group", accountGroup );
                put( "amount", AscendexCore.this.currencyToPrecision(code, amount) );
                put( "asset", Helpers.GetValue(currency, "id") );
                put( "fromAccount", finalFromId );
                put( "toAccount", finalToId );
            }};
            Object response = (this.v1PrivateAccountGroupPostTransfer(this.extend(request, parameters))).join();
            //
            //    { "code": "0" }
            //
            Object transferOptions = this.safeDict(this.options, "transfer", new java.util.HashMap<String, Object>() {{}});
            Object fillResponseFromRequest = this.safeBool(transferOptions, "fillResponseFromRequest", true);
            Object transfer = this.parseTransfer(response, currency);
            if (Helpers.isTrue(fillResponseFromRequest))
            {
                Helpers.addElementToObject(transfer, "fromAccount", fromAccount);
                Helpers.addElementToObject(transfer, "toAccount", toAccount);
                Helpers.addElementToObject(transfer, "amount", amount);
                Helpers.addElementToObject(transfer, "currency", code);
            }
            return transfer;
        });

    }

    public Object parseTransfer(Object transfer, Object... optionalArgs)
    {
        //
        //    { "code": "0" }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object status = this.safeString(transfer, "code");
        Object currencyCode = this.safeCurrencyCode(null, currency);
        return new java.util.HashMap<String, Object>() {{
            put( "info", transfer );
            put( "id", null );
            put( "timestamp", null );
            put( "datetime", null );
            put( "currency", currencyCode );
            put( "amount", null );
            put( "fromAccount", null );
            put( "toAccount", null );
            put( "status", AscendexCore.this.parseTransferStatus(status) );
        }};
    }

    public Object parseTransferStatus(Object status)
    {
        if (Helpers.isTrue(Helpers.isEqual(status, "0")))
        {
            return "ok";
        }
        return "failed";
    }

    /**
     * @method
     * @name ascendex#fetchFundingHistory
     * @description fetch the history of funding payments paid and received on this account
     * @see https://ascendex.github.io/ascendex-futures-pro-api-v2/#funding-payment-history
     * @param {string} [symbol] unified market symbol
     * @param {int} [since] the earliest time in ms to fetch funding history for
     * @param {int} [limit] the maximum number of funding history structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.paginate] default false, when true will automatically paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#pagination-params)
     * @returns {object} a [funding history structure]{@link https://docs.ccxt.com/?id=funding-history-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchFundingHistory(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            (this.loadAccounts()).join();
            Object paginate = false;
            var paginateparametersVariable = this.handleOptionAndParams(parameters, "fetchFundingHistory", "paginate");
            paginate = ((java.util.List<Object>) paginateparametersVariable).get(0);
            parameters = ((java.util.List<Object>) paginateparametersVariable).get(1);
            if (Helpers.isTrue(paginate))
            {
                return (this.fetchPaginatedCallIncremental("fetchFundingHistory", symbol, since, limit, parameters, "page", 25)).join();
            }
            Object account = this.safeDict(this.accounts, 0, new java.util.HashMap<String, Object>() {{}});
            Object accountGroup = this.safeString(account, "id");
            Object request = new java.util.HashMap<String, Object>() {{
                put( "account-group", accountGroup );
            }};
            Object market = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "pageSize", limit);
            }
            Object response = (this.v2PrivateAccountGroupGetFuturesFundingPayments(this.extend(request, parameters))).join();
            //
            //     {
            //         "code": 0,
            //         "data": {
            //             "data": [
            //                 {
            //                     "timestamp": 1640476800000,
            //                     "symbol": "BTC-PERP",
            //                     "paymentInUSDT": "-0.013991178",
            //                     "fundingRate": "0.000173497"
            //                 },
            //             ],
            //             "page": 1,
            //             "pageSize": 3,
            //             "hasNext": true
            //         }
            //     }
            //
            Object data = this.safeDict(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object rows = this.safeList(data, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseIncomes(rows, market, since, limit);
        });

    }

